*{{tl|Floruit}}
*{{tl|Married in}}
*{{tl|Reign}}
*[[Tempore]]

==TemplateData==
{{templatedata header}}
<templatedata>
{
	"params": {
		"1": {
			"label": "year",
			"type": "string",
			"suggested": true,
			"description": "An approximate date",
			"example": "1965"
		},
		"2": {
			"label": "end year",
			"type": "string",
			"description": "Use when the start and end dates of a range are both approximate.",
			"example": "1980"
		},
		"sortable": {
			"label": "sortable",
			"description": "Set to “yes” for values in sortable tables",
			"suggestedvalues": [
				"yes"
			],
			"default": "yes"
		},
		"lk": {
			"label": "link",
			"description": "If ‘on’, a link is added to the wiktionary article for circa. If ‘off’, the c. does not link or tooltip “circa”. Should be set to ‘off’ for the second and subsequent uses of this template. (Values ‘yes’ or ‘no’ may also be used.)",
			"type": "string",
			"suggestedvalues": [
				"on",
				"off"
			]
		}
	},
	"paramOrder": [
		"1",
		"2",
		"lk",
		"sortable"
	],
	"description": "This template generates an abbreviation for circa."
}
</templatedata>

